/**
 * @param {string} text
 * @return {number}
 */
var maxNumberOfBalloons = function(text) {
    let b = 0;
    let a = 0;
    let l = 0;
    let o = 0;
    let n = 0;

    for (const char of text) {
        if (char === 'b') b++;
        else if (char === 'a') a++;
        else if (char === 'l') l++;
        else if (char === 'o') o++;
        else if (char === 'n') n++;
    }

    return Math.min(
        b,
        a,
        Math.floor(l / 2),
        Math.floor(o / 2),
        n,
    );
};

/**
 * @param {string} text
 * @return {number}
 */
var maxNumberOfBalloons = function(text) {
    const arr = Array(26).fill(0);

    for (let i = 0; i < text.length; i++) {
        arr[text.charCodeAt(i) - 97]++;
    }

    return Math.min(
        arr['b'.charCodeAt(0) - 97],
        arr['a'.charCodeAt(0) - 97],
        Math.floor(arr['l'.charCodeAt(0) - 97] / 2),
        Math.floor(arr['o'.charCodeAt(0) - 97] / 2),
        arr['n'.charCodeAt(0) - 97],
    );
};
